#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) { return (*(int*)a - *(int*)b); }
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, k;
        scanf("%d %d", &n, &k);
        int arr[n];
        for (int i = 0; i < n; i++) {
            scanf("%d", &arr[i]);
        }
        qsort(arr, n, sizeof(int), compare);
        int count = 0;
        for (int i = 0; i < n - 1; i++) {
            if (arr[i + 1] - arr[i] < k) {
                count++;
                i++;
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

